#include <iostream>
#include <string>
#include <stdexcept>

// Function that might throw an exception
int divide(int a, int b) {
    if (b == 0) {
        throw std::runtime_error("Division by zero!");
    }
    return a / b;
}

// Function that might throw different exceptions
int getValueAt(std::vector<int>& vec, int index) {
    if (index < 0 || index >= vec.size()) {
        throw std::out_of_range("Index out of bounds!");
    }
    return vec[index];
}

int main() {
    std::cout << "=== Exceptions — try, catch, throw ===" << std::endl;

    // 1. Basic try-catch
    std::cout << "\n--- Basic Exception ---" << std::endl;
    try {
        int result = divide(10, 0);
        std::cout << "Result: " << result << std::endl;
    } catch (const std::exception& e) {
        std::cout << "❌ Caught exception: " << e.what() << std::endl;
    }

    // 2. Multiple catches
    std::cout << "\n--- Multiple Catches ---" << std::endl;
    std::vector<int> numbers = {10, 20, 30};

    try {
        std::cout << "Value at index 5: " << getValueAt(numbers, 5) << std::endl;
    } catch (const std::out_of_range& e) {
        std::cout << "❌ Out of range: " << e.what() << std::endl;
    } catch (const std::exception& e) {
        std::cout << "❌ General error: " << e.what() << std::endl;
    }

    // 3. Successful operation
    std::cout << "\n--- Successful Operation ---" << std::endl;
    try {
        int result = divide(10, 2);
        std::cout << "10 / 2 = " << result << std::endl;

        int val = getValueAt(numbers, 1);
        std::cout << "Value at index 1: " << val << std::endl;
    } catch (const std::exception& e) {
        std::cout << "❌ Error: " << e.what() << std::endl;
    }

    // 4. Catch all
    std::cout << "\n--- Catch All ---" << std::endl;
    try {
        throw 42;  // Throwing an int
    } catch (int e) {
        std::cout << "❌ Caught int: " << e << std::endl;
    } catch (...) {
        std::cout << "❌ Caught unknown exception" << std::endl;
    }

    // 5. Rethrowing
    std::cout << "\n--- Rethrowing ---" << std::endl;
    try {
        try {
            throw std::runtime_error("Inner error");
        } catch (const std::exception& e) {
            std::cout << "Inner catch: " << e.what() << std::endl;
            throw;  // Rethrow
        }
    } catch (const std::exception& e) {
        std::cout << "Outer catch: " << e.what() << std::endl;
    }

    // 6. Exceptions in games
    std::cout << "\n--- Game Example ---" << std::endl;
    try {
        int playerHealth = 100;
        int damage = 150;

        if (damage > playerHealth) {
            throw std::runtime_error("Player would die!");
        }

        playerHealth -= damage;
        std::cout << "Player health: " << playerHealth << std::endl;
    } catch (const std::exception& e) {
        std::cout << "⚠️ " << e.what() << " - Setting health to 0" << std::endl;
    }

    std::cout << "\n--- Exception Types ---" << std::endl;
    std::cout << "✅ std::exception — base class" << std::endl;
    std::cout << "✅ std::runtime_error — runtime errors" << std::endl;
    std::cout << "✅ std::out_of_range — out of bounds" << std::endl;
    std::cout << "✅ std::invalid_argument — invalid input" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>

int main() {
    try {
        throw std::runtime_error("Oops!");
    } catch (...) {
        // Swallowed!
        // No way to know what happened!
    }

    // Code continues — but we don't know if there was an error
    std::cout << "Continue..." << std::endl;
    return 0;
}

phase2.explanation:
Swallowing exceptions is dangerous! You catch everything but do nothing with it.

**The fix:**
```cpp
try {
    throw std::runtime_error("Oops!");
} catch (const std::exception& e) {
    std::cout << "Error: " << e.what() << std::endl;
    // At least log it!
}
```

**PlusPlus-chan says:**
"Never swallow exceptions. Always log or handle them."

phase3.solution:
#include <iostream>
#include <stdexcept>
#include <string>

int divide(int a, int b) {
    if (b == 0) {
        throw std::runtime_error("Division by zero!");
    }
    return a / b;
}

int getCharacter(int index) {
    std::string chars = "ABCDE";
    if (index < 0 || index >= 5) {
        throw std::out_of_range("Index out of bounds!");
    }
    return chars[index];
}

int main() {
    std::cout << "=== Exception Handling ===" << std::endl;

    try {
        int result = divide(10, 0);
        std::cout << "Result: " << result << std::endl;
    } catch (const std::runtime_error& e) {
        std::cout << "❌ Runtime error: " << e.what() << std::endl;
    }

    try {
        int result = divide(15, 3);
        std::cout << "15 / 3 = " << result << std::endl;
    } catch (const std::runtime_error& e) {
        std::cout << "❌ Runtime error: " << e.what() << std::endl;
    }

    try {
        char ch = getCharacter(10);
        std::cout << "Character: " << ch << std::endl;
    } catch (const std::out_of_range& e) {
        std::cout << "❌ Out of range: " << e.what() << std::endl;
    }

    try {
        char ch = getCharacter(2);
        std::cout << "Character at index 2: " << ch << std::endl;
    } catch (const std::out_of_range& e) {
        std::cout << "❌ Out of range: " << e.what() << std::endl;
    }

    return 0;
}
